import (
	"fmt"
	"sync"
)

func source(vals ...int) <-chan int {
	ch := make(chan int, len(vals))
	for _, v := range vals {
		ch <- v
	}
	close(ch)
	return ch
}

func merge(channels ...<-chan int) <-chan int {
	out := make(chan int)
	var wg sync.WaitGroup
	for _, ch := range channels {
		wg.Add(1)
		go func(c <-chan int) {
			defer wg.Done()
			for v := range c {
				out <- v
			}
		}(ch)
	}
	go func() {
		wg.Wait()
		close(out)
	}()
	return out
}

func main() {
	ch1 := source(1, 2, 3)
	ch2 := source(4, 5, 6)
	// TODO: merge ch1, ch2, and source(7, 8, 9)
	merged := merge(ch1, ch2)

	total := 0
	for v := range merged {
		total += v
	}
	fmt.Println("Total:", total)
}

