import (
	"context"
	"fmt"
	"time"
)

func worker(ctx context.Context, id int, delay time.Duration, results chan<- string) {
	select {
	case <-time.After(delay):
		results <- fmt.Sprintf("Worker %d finished first", id)
	case <-ctx.Done():
		fmt.Printf("Worker %d cancelled\n", id)
	}
}

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	results := make(chan string, 1)

	go worker(ctx, 1, 80*time.Millisecond, results)
	go worker(ctx, 2, 200*time.Millisecond, results)

	winner := <-results
	fmt.Println(winner)
	cancel()
	time.Sleep(50 * time.Millisecond)
}

