import (
	"fmt"
	"sync"
)

func main() {
	sem := make(chan struct{}, 3)
	var wg sync.WaitGroup
	active := 0
	var mu sync.Mutex

	for i := 1; i <= 10; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			sem <- struct{}{}
			defer func() { <-sem }()

			mu.Lock()
			active++
			if active > 3 {
				fmt.Printf("VIOLATION: %d goroutines active!\n", active)
			}
			mu.Unlock()

			mu.Lock()
			active--
			mu.Unlock()
		}(i)
	}

	wg.Wait()
	fmt.Println("All goroutines done, max 3 ran concurrently")
}

