import (
	"fmt"
	"sync"
	"time"
)

func server(jobs <-chan int, shutdown <-chan struct{}, wg *sync.WaitGroup) {
	defer wg.Done()
	for {
		select {
		case job, ok := <-jobs:
			if !ok {
				fmt.Println("Server: job queue empty, exiting")
				return
			}
			time.Sleep(20 * time.Millisecond)
			fmt.Printf("Server: completed job %d\n", job)
		case <-shutdown:
			fmt.Println("Server: shutdown signal received, draining...")
			for job := range jobs {
				time.Sleep(20 * time.Millisecond)
				fmt.Printf("Server: completed job %d\n", job)
			}
			fmt.Println("Server: all jobs drained, exiting")
			return
		}
	}
}

func main() {
	jobs := make(chan int, 5)
	shutdown := make(chan struct{})
	var wg sync.WaitGroup

	for i := 1; i <= 5; i++ {
		jobs <- i
	}
	close(jobs)

	wg.Add(1)
	go server(jobs, shutdown, &wg)

	time.Sleep(50 * time.Millisecond)
	close(shutdown)

	wg.Wait()
	fmt.Println("Main: clean exit")
}

